var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"오늘 임무는 마을에 나타난 침식체를 전부 죽이는 것.","JPN":"今日の任務は村に現われた侵食体を全部殺すこと。","ENG":"Today's mission is to kill all the C.O.s that appeared in the village.","TWN":"今天的任務是消滅出現在村莊裡的所有侵蝕體。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"생존자는 한 명도 남겨놓지 말랬어요.","JPN":"生存者は一人も残さないようにと言われました。","ENG":"They said not to leave any survivors.","TWN":"一個倖存者都不能放過。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"어라? 평범한 아이가 있었어요!","JPN":"あれ？　普通の子どもがいました！","ENG":"Huh? There's a normal kid here!","TWN":"咦？有個普通的孩子！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"너무… 너무 사랑스러워요!","JPN":"とても……とても可愛らしいです！","ENG":"She's... she's adorable!","TWN":"非常…非常可愛！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"아이는 우리들의 가족이 되었어요. 너무 너무 예쁘고 사랑스러운 아이.","JPN":"子どもは私たちの家族になりました。ものすごくキレイで可愛らしい子。","ENG":"She became our family. Such a lovely child she was.","TWN":"非常非常可愛的孩子成為我們的家人後，"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"어라? 아이는 일주일도 못가 죽어버렸어요.","JPN":"あれ？　子どもは一週間も持たずに死んじゃいました。","ENG":"Oh? But she didn't last a week.","TWN":"嗯？不到一週就死了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"잘 대해줬는데… 어째서?","JPN":"優しくしてやったのに……どうして？","ENG":"Why...? I treated her so well…","TWN":"明明對她很好……為什麼？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"그래도 드레카는 포기하지 않고, 계속 열심히 했어요.","JPN":"それでもドレカは諦めず、ずっと頑張りました。","ENG":"But Dreka didn't give up and worked hard.","TWN":"即便如此，德蕾卡也沒有放棄，在繼續努力呢。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"열심히, 아주 열심히… 노력했어요.","JPN":"一生懸命、とても一生懸命に……努力しました。","ENG":"I did my best... and worked so hard.","TWN":"努力，非常…非常…努力。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"이면세계의 침식체들, 다른 마을에 모여있는 아이들과, 그림자도 다 죽였어요.","JPN":"裏世界の侵食体、他の村に集まっている子どもたちと、シャドウも全部殺しました。","ENG":"The C.O.s in Counterside, the children gathered in the village, and even the Shadows. I killed them all.","TWN":"異界的侵蝕體、村裡的孩子們，還有暗影都被德蕾卡殺死了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"박사님이 칭찬해 줬어요. 드레카는 최고의 영웅이래요!","JPN":"博士に褒めてもらったんです。ドレカは最高の英雄だって！","ENG":"The doctor praised me. He said that Dreka was the greatest hero!","TWN":"博士誇獎了我，說德蕾卡是最棒的英雄！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"더 이상 드레카와 에바 언니는 아프지 않을거래요!","JPN":"もうドレカとエヴァ姉さんは苦しまなくていいって！","ENG":"He also said that Dreka and Eva won't be in pain anymore!","TWN":"德蕾卡和耶娃姊姊再也不會痛苦了！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"박사님과 모두들, 저희들에게 상냥하게 대해줬어요.","JPN":"博士とみんな、私たちに優しくしてくれました。","ENG":"The doctor and everyone treated us so well.","TWN":"博士和大家都對我們很溫柔。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"히힛, 드레카는 너무 행복해요!","JPN":"ひひっ、ドレカはとても幸せです！","ENG":"Hehe! Dreka is so happy!","TWN":"嘻嘻，德蕾卡好幸福！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"드, 드레카…!","JPN":"ド、ドレカ……！","ENG":"D-Dreka...!","TWN":"德，德蕾卡……！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"다행이다 언니… 무사했구나?","JPN":"よかった、姉さん……無事だったんだ？","ENG":"Sis... You're safe...","TWN":"是耶娃姊姊……你沒事吧？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"에바!!","JPN":"エヴァ！！","ENG":"Eva!!","TWN":"耶娃！！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"히, 히익!","JPN":"ひ、ひいっ！","ENG":"E-eeek!","TWN":"欸？欸！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"연구소로 가자! 박사님이 우릴 구해주실 거야!","JPN":"研究所に行こう！　博士が私たちを助けてくれるはずだよ！","ENG":"Let's go back to the lab! The doctor will save us!","TWN":"快，快去研究所！博士會救我們的！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"우, 움직일 수 있겠어?","JPN":"う、動ける？","ENG":"C-can you move?","TWN":"能，能動嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"후훗. 그래야겠네.","JPN":"ふふっ。そうしなくちゃだね。","ENG":"Haha. I also think we should do that.","TWN":"呵呵，是啊。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"근데 마브카 언니는 어떻게 따돌리지?","JPN":"でも、マブカさんはどうやって撒くの？","ENG":"But how are we going to get rid of Mavka?","TWN":"但是怎麼甩掉瑪卡姊姊呢？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"그, 그야… 열심히 뛰어야 하지 않을까...?","JPN":"そ、それは……頑張って走るしか……？","ENG":"B-by... running really fast...?","TWN":"那，那就……拼命跑吧……？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"흐응~ 그런데 마브카 언니는 날아다니기까지 하는걸?","JPN":"ふーん。でもマブカさんは飛び回るんだよ？","ENG":"Hmm... But can't Mavka fly?","TWN":"嗯～但是瑪卡姊姊還會飛呢？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"누군가 <color=#ffd34c>미끼</color>라도 되어주지 않으면 붙잡히고 말 거야.","JPN":"誰かが<color=#ffd34c>エサ</color>になってくれないと捕まっちゃう。","ENG":"Someone has to become <color=#ffd34c>the bait</color> so the other doesn't get caught.","TWN":"如果沒有人<color=#ffd34c>當誘餌</color>，我們就會被抓住。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"……어?!","JPN":"……え！？","ENG":"...Huh?!","TWN":"……呃？！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"EVA_DOLL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};